import time
import functools

def timing_decorator(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        start_time = time.perf_counter()
        result = func(*args, **kwargs)
        end_time = time.perf_counter()
        elapsed_time = end_time - start_time
        print(f"'{func.__name__}' fonksiyonu {elapsed_time:.4f} saniyede tamamlandı.")
        return result
    return wrapper

if __name__ == '__main__':
    @timing_decorator
    def example_function_1():
        time.sleep(1.5)
        print("Example function 1 çalıştı.")

    @timing_decorator
    def example_function_2(name, iterations):
        print(f"Example function 2 çalıştı, isim: {name}")
        for _ in range(iterations):
            sum(range(10000)) # Biraz işlem yükü
        time.sleep(0.5)
        return f"Merhaba, {name}!"

    print("Fonksiyon 1 çağrılıyor...")
    example_function_1()
    print("-" * 30)

    print("Fonksiyon 2 çağrılıyor...")
    return_value = example_function_2("Python", 500)
    print(f"Fonksiyon 2'den dönen değer: {return_value}")
    print("-" * 30)

    @timing_decorator
    def fast_function():
        pass

    print("Hızlı fonksiyon çağrılıyor...")
